# ============================================================
# Data Encryption for sensitive values stored in Redis
# ============================================================
class DataProtector:
    """
    Handles encryption/hashing of sensitive data before storing in Redis.
    Uses HMAC for integrity verification and basic obfuscation.
    For production, integrate with a proper KMS (AWS KMS, HashiCorp Vault, etc.)
    """

    def __init__(self, encryption_key: str):
        if not encryption_key:
            raise ValueError("Encryption key must not be empty")
        self._key = encryption_key.encode('utf-8')

    def hash_token(self, token: str) -> str:
        """Create a one-way hash of a token for use as a Redis key lookup."""
        return hmac.new(self._key, token.encode('utf-8'), hashlib.sha256).hexdigest()

    def protect_value(self, data: dict) -> str:
        """
        Serialize and sign data before storing.
        In production, replace with proper AES-256-GCM encryption via a KMS.
        """
        payload = json.dumps(data, sort_keys=True)
        signature = hmac.new(self._key, payload.encode('utf-8'), hashlib.sha256).hexdigest()
        protected = json.dumps({"payload": payload, "sig": signature})
        return protected

    def unprotect_value(self, protected_data: str) -> Optional[dict]:
        """Verify signature and deserialize data."""
        try:
            wrapper = json.loads(protected_data)
            payload = wrapper["payload"]
            expected_sig = hmac.new(self._key, payload.encode('utf-8'), hashlib.sha256).hexdigest()
            if not hmac.compare_digest(expected_sig, wrapper["sig"]):
                logger.warning("Data integrity check failed - possible tampering detected")
                return None
            return json.loads(payload)
        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Failed to unprotect value: {e}")
            return None


