class RedisClusterManager:
    """Manages connections to a Redis cluster with retry logic and health checks."""

    def __init__(self, config: Config):
        self._config = config
        self._cluster: Optional[RedisCluster] = None
        self._connect()

    def _parse_cluster_nodes(self):
        """Parse cluster node addresses from configuration."""
        nodes = []
        for node_str in self._config.REDIS_CLUSTER_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def _connect(self):
        """Establish connection to Redis cluster."""
        nodes = self._parse_cluster_nodes()
        logger.info(f"Connecting to Redis cluster nodes: {[(n.host, n.port) for n in nodes]}")

        connection_kwargs = {
            "startup_nodes": nodes,
            "password": self._config.REDIS_PASSWORD,
            "socket_timeout": self._config.REDIS_SOCKET_TIMEOUT,
            "socket_connect_timeout": self._config.REDIS_SOCKET_CONNECT_TIMEOUT,
            "retry_on_timeout": self._config.REDIS_RETRY_ON_TIMEOUT,
            "decode_responses": True,
            "skip_full_coverage_check": True,
        }

        if self._config.REDIS_SSL:
            connection_kwargs.update({
                "ssl": True,
                "ssl_ca_certs": self._config.REDIS_SSL_CA_CERTS,
                "ssl_certfile": self._config.REDIS_SSL_CERTFILE,
                "ssl_keyfile": self._config.REDIS_SSL_KEYFILE,
                "ssl_cert_reqs": "required",
            })

        max_retries = 3
        for attempt in range(1, max_retries + 1):
            try:
                self._cluster = RedisCluster(**connection_kwargs)
                # Verify connection
                self._cluster.ping()
                logger.info("Successfully connected to Redis cluster")
                return
            except (ConnectionError, TimeoutError, RedisError) as e:
                logger.error(f"Redis connection attempt {attempt}/{max_retries} failed: {e}")
                if attempt == max_retries:
                    raise
                time.sleep(2 ** attempt)  # Exponential backoff

    @property
    def client(self) -> RedisCluster:
        """Get the Redis cluster client, reconnecting if necessary."""
        if self._cluster is None:
            self._connect()
        try:
            self._cluster.ping()
        except (ConnectionError, TimeoutError, RedisError):
            logger.warning("Redis connection lost, attempting reconnection...")
            self._connect()
        return self._cluster

    def health_check(self) -> Dict[str, Any]:
        """Perform a health check on the Redis cluster."""
        try:
            start = time.time()
            self.client.ping()
            latency_ms = (time.time() - start) * 1000
            cluster_info = self.client.cluster_info()
            return {
                "status": "healthy",
                "latency_ms": round(latency_ms, 2),
                "cluster_state": cluster_info.get("cluster_state", "unknown"),
                "cluster_slots_assigned": cluster_info.get("cluster_slots_assigned", 0),
                "cluster_known_nodes": cluster_info.get("cluster_known_nodes", 0),
            }
        except Exception as e:
            return {
                "status": "unhealthy",
                "error": str(e),
            }

    def close(self):
        """Close the Redis cluster connection."""
        if self._cluster:
            self._cluster.close()
            self._cluster = None
            logger.info("Redis cluster connection closed")


